import{c as a,Q as t,j as i,m as r}from"./chunks/framework.CdiUUa3G.js";const p=JSON.parse('{"title":"ADR-004 — Hash-based client-side routing","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-004.md","filePath":"adr/ADR-004.md"}'),o={name:"adr/ADR-004.md"};function s(n,e,d,c,l,h){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="adr-004-—-hash-based-client-side-routing" tabindex="-1">ADR-004 — Hash-based client-side routing <a class="header-anchor" href="#adr-004-—-hash-based-client-side-routing" aria-label="Permalink to &quot;ADR-004 — Hash-based client-side routing&quot;">​</a></h1><blockquote><p>Status · <strong>Superseded by ADR-013 (History API via SvelteKit router)</strong> Date · 2026-04-01 · Superseded April 2026 TA anchor · §stack · §components/router</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Six screens need to be navigable by URL. The application is served as static files by nginx. Deep-linking must work without server-side redirect logic.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Hash-based routing. Routes are <code>#/screen</code> with optional query params (<code>#/fly?mission=curiosity</code>). The router reads <code>window.location.hash</code> and <code>hashchange</code> events.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Hash routing works without server-side configuration — nginx serves <code>index.html</code> and the browser handles the hash fragment client-side. History API routing requires either a server-side catch-all redirect or a build step that generates per-route HTML files. Hash routing is simpler and more robust for a static deployment.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li>History API routing — cleaner URLs; requires server-side redirect config or build-time static generation. Adds server config complexity for no user-facing benefit in v1.</li><li>No routing (direct HTML files per screen) — prototypes work this way; not viable for production where state must be shared between screens and URLs must be bookmarkable.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: works with any static file server; no nginx configuration needed for routing. Negative: URLs contain <code>#</code>; slightly less clean aesthetically. History API routing is a v2 candidate (RFC-001).</p>',12)])])}const b=a(o,[["render",s]]);export{p as __pageData,b as default};
